return (function prepareQueries() {
  const MS_DAY = 24 * 60 * 60 * 1000;
  const TZ_OFFSET_MS = 9 * 60 * 60 * 1000;

  function pad(value) {
    return String(value).padStart(2, '0');
  }

  function formatDateJst(date) {
    const jst = new Date(date.getTime() + TZ_OFFSET_MS);
    return `${jst.getUTCFullYear()}-${pad(jst.getUTCMonth() + 1)}-${pad(jst.getUTCDate())}`;
  }

  function mondayStartUtcForPreviousWeek(now = new Date()) {
    const jstNow = new Date(now.getTime() + TZ_OFFSET_MS);
    const day = jstNow.getUTCDay();
    const daysSinceMonday = (day + 6) % 7;
    const thisMondayJstMidnightUtcMs = Date.UTC(
      jstNow.getUTCFullYear(),
      jstNow.getUTCMonth(),
      jstNow.getUTCDate() - daysSinceMonday,
      0,
      0,
      0,
    ) - TZ_OFFSET_MS;
    return new Date(thisMondayJstMidnightUtcMs - 7 * MS_DAY);
  }

  function sqlDate(date) {
    return date.toISOString().replace('T', ' ').replace('.000Z', '');
  }

  function escapeSql(value) {
    return String(value).replace(/\\/g, '\\\\').replace(/'/g, "\\'");
  }

  const weekStart = mondayStartUtcForPreviousWeek();
  const weekEnd = new Date(weekStart.getTime() + 7 * MS_DAY);
  const previousWeekStart = new Date(weekStart.getTime() - 7 * MS_DAY);
  const previousWeekEnd = weekStart;
  const startUtc = escapeSql(sqlDate(weekStart));
  const endUtc = escapeSql(sqlDate(weekEnd));
  const previousStartUtc = escapeSql(sqlDate(previousWeekStart));
  const previousEndUtc = escapeSql(sqlDate(previousWeekEnd));

  return [{
    json: {
      week_start_jst: formatDateJst(weekStart),
      week_end_jst: formatDateJst(new Date(weekEnd.getTime() - MS_DAY)),
      week_start_utc_iso: weekStart.toISOString(),
      week_end_utc_iso: weekEnd.toISOString(),
      totals_query: `SELECT countIf(event = '$pageview') AS pageviews, uniqIf(distinct_id, event = '$pageview') AS unique_visitors, count() AS total_events FROM events WHERE timestamp >= toDateTime('${startUtc}', 'UTC') AND timestamp < toDateTime('${endUtc}', 'UTC')`,
      previous_totals_query: `SELECT countIf(event = '$pageview') AS pageviews, uniqIf(distinct_id, event = '$pageview') AS unique_visitors FROM events WHERE timestamp >= toDateTime('${previousStartUtc}', 'UTC') AND timestamp < toDateTime('${previousEndUtc}', 'UTC')`,
      top_pages_query: `SELECT replaceRegexpOne(toString(properties['$current_url']), '^https?://[^/]+', '') AS path, count() AS pageviews, uniq(distinct_id) AS visitors FROM events WHERE event = '$pageview' AND timestamp >= toDateTime('${startUtc}', 'UTC') AND timestamp < toDateTime('${endUtc}', 'UTC') GROUP BY path ORDER BY pageviews DESC LIMIT 10`,
      referrers_query: `SELECT coalesce(nullIf(toString(properties['$referrer']), ''), '(none)') AS referrer, coalesce(nullIf(toString(properties['utm_source']), ''), '(none)') AS utm_source, coalesce(nullIf(toString(properties['utm_campaign']), ''), '(none)') AS utm_campaign, count() AS pageviews, uniq(distinct_id) AS visitors FROM events WHERE event = '$pageview' AND timestamp >= toDateTime('${startUtc}', 'UTC') AND timestamp < toDateTime('${endUtc}', 'UTC') GROUP BY referrer, utm_source, utm_campaign ORDER BY pageviews DESC LIMIT 10`,
      events_query: `SELECT event, count() AS count, uniq(distinct_id) AS visitors FROM events WHERE timestamp >= toDateTime('${startUtc}', 'UTC') AND timestamp < toDateTime('${endUtc}', 'UTC') GROUP BY event ORDER BY count DESC LIMIT 30`,
      cta_detail_query: `SELECT event, properties['source_path'] AS source_path, properties['guide_path'] AS guide_path, properties['cta_label'] AS cta_label, properties['cta_href'] AS cta_href, count() AS count FROM events WHERE event IN ('bsj_guide_cta_click', 'bsj_lead_magnet_signup_click', 'bsj_phrase_cards_signup_click', 'bsj_tattoo_kit_signup_click', 'bsj_confirmation_service_cta_click', 'bsj_product_teaser_click', 'bsj_external_source_link_click', 'bsj_tag_click', 'bsj_map_link_click') AND timestamp >= toDateTime('${startUtc}', 'UTC') AND timestamp < toDateTime('${endUtc}', 'UTC') GROUP BY event, source_path, guide_path, cta_label, cta_href ORDER BY count DESC LIMIT 20`,
    },
  }];
})();

return (function buildReportRow() {
  const MS_DAY = 24 * 60 * 60 * 1000;
  const TZ_OFFSET_MS = 9 * 60 * 60 * 1000;

  function pad(value) {
    return String(value).padStart(2, '0');
  }

  function formatJst(date) {
    const jst = new Date(date.getTime() + TZ_OFFSET_MS);
    return `${jst.getUTCFullYear()}-${pad(jst.getUTCMonth() + 1)}-${pad(jst.getUTCDate())} ${pad(jst.getUTCHours())}:${pad(jst.getUTCMinutes())}:${pad(jst.getUTCSeconds())}`;
  }

  function parseJst(value) {
    if (!value) return null;
    const text = String(value).trim();
    const match = text.match(/^(\d{4})-(\d{1,2})-(\d{1,2})(?:[ T](\d{1,2}):(\d{2})(?::(\d{2}))?)?/);
    if (!match) return null;
    const [, y, m, d, hh = '0', mm = '0', ss = '0'] = match;
    return new Date(Date.UTC(Number(y), Number(m) - 1, Number(d), Number(hh), Number(mm), Number(ss)) - TZ_OFFSET_MS);
  }

  function summarizeRows(rows, formatter) {
    if (!rows.length) return '';
    return rows.map(formatter).join(' | ');
  }

  function getResults(nodeName) {
    const nodeJson = $(nodeName).first().json || {};
    return Array.isArray(nodeJson.results) ? nodeJson.results : [];
  }

  const context = $('Code: Prepare Report Queries').first().json;
  const weekStart = new Date(context.week_start_utc_iso);
  const weekEnd = new Date(context.week_end_utc_iso);

  const totalsRows = getResults('PostHog: Totals');
  const previousTotalsRows = getResults('PostHog: Previous Totals');
  const pageRows = getResults('PostHog: Top Pages');
  const referrerRows = getResults('PostHog: Referrers');
  const eventRows = getResults('PostHog: Events');
  const ctaRows = getResults('PostHog: CTA Detail');

  const totals = totalsRows[0] || [0, 0, 0];
  const previousTotals = previousTotalsRows[0] || [0, 0];
  const eventCounts = Object.fromEntries(eventRows.map(([event, count]) => [event, Number(count)]));

  const threadRows = $('Sheets: Read Threads Queue').all().map((item) => item.json || {});
  const postedRows = threadRows.filter((row) => {
    const postedAt = parseJst(row.posted_at_jst || row.last_attempt_at);
    return row.status === 'posted' && postedAt && postedAt >= weekStart && postedAt < weekEnd;
  });
  const linkedPostedRows = postedRows.filter((row) => row.cta_type === 'site_link' || String(row.cta_url || '').startsWith('http'));

  const topPages = summarizeRows(pageRows, ([path, pv, visitors]) => `${path || '(unknown)'}: ${pv} PV / ${visitors} visitors`);
  const topReferrers = summarizeRows(referrerRows, ([referrer, utmSource, utmCampaign, pv]) => `${utmSource !== '(none)' ? utmSource : referrer}: ${pv} PV${utmCampaign !== '(none)' ? ` (${utmCampaign})` : ''}`);
  const topCtas = summarizeRows(ctaRows, ([event, sourcePath, guidePath, label, href, count]) => `${event}${label ? ` / ${label}` : ''}${sourcePath || guidePath ? ` @ ${sourcePath || guidePath}` : ''}: ${count}`);

  const pageviews = Number(totals[0] || 0);
  const uniqueVisitors = Number(totals[1] || 0);
  const totalEvents = Number(totals[2] || 0);
  const previousPageviews = Number(previousTotals[0] || 0);
  const previousVisitors = Number(previousTotals[1] || 0);
  const pvDelta = previousPageviews ? `${pageviews - previousPageviews >= 0 ? '+' : ''}${pageviews - previousPageviews} vs prior week` : 'no prior-week baseline';
  const visitorDelta = previousVisitors ? `${uniqueVisitors - previousVisitors >= 0 ? '+' : ''}${uniqueVisitors - previousVisitors} vs prior week` : 'no prior-week baseline';

  const leadClicks = (eventCounts.bsj_lead_magnet_signup_click || 0) + (eventCounts.bsj_phrase_cards_signup_click || 0) + (eventCounts.bsj_tattoo_kit_signup_click || 0);
  const guideClicks = eventCounts.bsj_guide_cta_click || 0;
  const affiliateClicks = (eventCounts.bsj_external_source_link_click || 0) + (eventCounts.bsj_product_teaser_click || 0);
  const tagClicks = eventCounts.bsj_tag_click || 0;
  const mapClicks = eventCounts.bsj_map_link_click || 0;

  const interpretation = [
    `${pageviews} pageviews and ${uniqueVisitors} visitors (${pvDelta}; visitors: ${visitorDelta}).`,
    leadClicks ? `Lead magnet clicks appeared (${leadClicks}).` : 'No lead magnet clicks recorded.',
    postedRows.length ? `Threads posted ${postedRows.length} times; ${linkedPostedRows.length} linked posts.` : 'No Threads posts recorded as posted in the queue for this week.',
  ].join(' ');

  const internalTrafficNote = uniqueVisitors <= 5
    ? 'Traffic is still small and may include owner/admin checks. Treat directionally, not as proof.'
    : 'Sample is larger, but check owner/admin traffic before making strong conclusions.';

  const recommendedActions = [
    topPages ? `Double down on the strongest page/topic: ${pageRows[0]?.[0] || 'unknown'}.` : 'Publish and distribute enough content to establish a first baseline.',
    leadClicks ? 'Keep lead magnet CTAs visible on guide pages and compare beehiiv signups against clicks.' : 'Add or improve contextual lead magnet CTAs on pages receiving traffic.',
    linkedPostedRows.length ? 'Check Threads-linked URLs in PostHog with UTM tags next week.' : 'Ensure roughly 1 in 3 Threads posts has a natural BSJ guide link once the account warms up.',
  ].join(' ');

  const rawReportMarkdown = `# BSJ weekly analytics report\n\nWeek: ${context.week_start_jst} to ${context.week_end_jst} JST\nGenerated: ${formatJst(new Date())} JST\n\n## Summary\n- Pageviews: ${pageviews}\n- Unique visitors: ${uniqueVisitors}\n- Total events: ${totalEvents}\n- Lead magnet clicks: ${leadClicks}\n- Guide CTA clicks: ${guideClicks}\n- Affiliate/product clicks: ${affiliateClicks}\n- Threads posted: ${postedRows.length}\n- Threads linked posts: ${linkedPostedRows.length}\n\n## Top pages\n${topPages || 'No pageviews recorded.'}\n\n## Referrers / UTM\n${topReferrers || 'No referrer data recorded.'}\n\n## CTA events\n${topCtas || 'No CTA events recorded.'}\n\n## Interpretation\n${interpretation}\n\n## Internal traffic note\n${internalTrafficNote}\n\n## Recommended actions\n${recommendedActions}\n`;

  return [{
    json: {
      week_start_jst: context.week_start_jst,
      week_end_jst: context.week_end_jst,
      generated_at_jst: formatJst(new Date()),
      pageviews,
      unique_visitors: uniqueVisitors,
      total_events: totalEvents,
      lead_magnet_clicks: leadClicks,
      guide_cta_clicks: guideClicks,
      affiliate_cta_clicks: affiliateClicks,
      tag_clicks: tagClicks,
      map_clicks: mapClicks,
      threads_posted: postedRows.length,
      threads_linked_posted: linkedPostedRows.length,
      top_pages: topPages,
      top_referrers: topReferrers,
      top_ctas: topCtas,
      internal_traffic_note: internalTrafficNote,
      interpretation,
      recommended_actions: recommendedActions,
      raw_report_markdown: rawReportMarkdown,
    },
  }];
})();
